import{_ as t,o as a,c as o,ae as r}from"./chunks/framework.B6gjLfeO.js";const m=JSON.parse('{"title":"Time-Based Activity Targeting for Journeys","description":"","frontmatter":{"title":"Time-Based Activity Targeting for Journeys","slug":"time-based-activity-tracking-for-journeys"},"headers":[],"relativePath":"account-hub/time-based-activity-tracking-for-journeys.md","filePath":"account-hub/time-based-activity-tracking-for-journeys.md"}'),i={name:"account-hub/time-based-activity-tracking-for-journeys.md"};function s(n,e,u,c,d,l){return a(),o("div",null,[...e[0]||(e[0]=[r('<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch has updated the default &quot;Has visited web&quot; rule in Journeys to provide more granular control over engagement targeting. You can now define audiences based on the frequency of their visits.</p><h2 id="what-s-new" tabindex="-1">What’s new <a class="header-anchor" href="#what-s-new" aria-label="Permalink to &quot;What’s new&quot;">​</a></h2><ul><li><strong>Day-based frequency targeting:</strong> Target users based on how many days they have visited your website out of the last 63 days (for example, users who visited at least 5 days out of the last 30).</li><li><strong>Flexible comparison options:</strong> Define your criteria using &quot;greater than,&quot; &quot;equal to,&quot; &quot;less than,&quot; or &quot;in between&quot; logic to capture the exact engagement level you want.</li><li><strong>Days or Time toggle:</strong> A drop-down menu lets you switch between &quot;Days&quot; and &quot;Time&quot; modes. “Time&quot; mode is not compatible with time-bound banners. When selected, the &quot;out of the last Y days&quot; option is hidden.</li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>Time-based activity targeting tracks visits across the user&#39;s entire history, not a defined time period. This does not apply to day-based targeting.</p></div><p>Learn more in our <a href="https://help.branch.io/marketer-hub/docs/create-journey-banner-or-interstitial" target="_blank" rel="noreferrer">Create Journeys Banners or Interstitials</a> article.</p>',6)])])}const g=t(i,[["render",s]]);export{m as __pageData,g as default};
